#include <bits/stdc++.h>
using namespace std;
vector<int> g[1002];
int n,m,e,v[1002];
bool b[1002];
bool dfs(int x){
    b[x]=true;
    int len=g[x].size();
    for(int i=0;i<len;i++)
        if(!v[g[x][i]] || (!b[v[g[x][i]]] && dfs(v[g[x][i]]))){
            v[g[x][i]]=x;
            return true;
        }
    return false;
}
int match(){
    int ans=0;
    for(int i=1;i<=n;i++){
        memset(b,false,sizeof(b));
        if(dfs(i))
            ans++;
    }
    return ans;
}
int main(){
    cin>>n>>m>>e;
    for(int i=1;i<=e;i++){
        int u,v;
        cin>>u>>v;
        g[u].push_back(v);
    }
    cout<<match();
    return 0;
}
